                Ratings = [5, 5, 4]
            },
            new()
            {
                Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
                Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nTomato sauce\nHeavy cream\nGarlic\nGinger\nOnion",
                Steps = "1. Marinate chicken in yogurt, garam masala, and turmeric for 1 hour.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger in a pan.\n4. Add tomato sauce and simmer for 15 minutes.\n5. Stir in cream and cooked chicken.\n6. Simmer 10 more minutes and serve with rice.",
                Ratings = [5, 4, 5, 5]
            },
            new()
            {
                Id = 4, Title = "Vegetable Pad Thai", Category = "Asian",
                Ingredients = "Rice noodles\nTofu\nBean sprouts\nGreen onions\nPeanuts\nLime\nSoy sauce\nTamarind paste\nBrown sugar\nGarlic",
                Steps = "1. Soak rice noodles in warm water for 20 minutes, then drain.\n2. Press and cube tofu, then pan-fry until golden.\n3. Make sauce: mix tamarind paste, soy sauce, and brown sugar.\n4. Stir-fry garlic, then add noodles and sauce.\n5. Toss in tofu and bean sprouts.\n6. Serve with crushed peanuts, green onions, and lime wedges.",
                Ratings = [4, 4, 3]
            },
            new()
            {
                Id = 5, Title = "Beef Tacos", Category = "Mexican",
                Ingredients = "Ground beef\nTaco shells\nLettuce\nTomato\nCheddar cheese\nSour cream\nCumin\nChili powder\nGarlic powder\nOnion",
                Steps = "1. Brown ground beef with diced onion in a skillet.\n2. Season with cumin, chili powder, and garlic powder.\n3. Warm taco shells in the oven.\n4. Fill shells with seasoned beef.\n5. Top with shredded lettuce, diced tomato, cheese, and sour cream.\n6. Serve with salsa and lime.",
                Ratings = [4, 5, 4, 5]
            },
            new()
            {
                Id = 6, Title = "Chocolate Lava Cake", Category = "Desserts",
                Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract",
                Steps = "1. Preheat oven to 425°F (220°C) and grease ramekins.\n2. Melt chocolate and butter together.\n3. Whisk eggs and sugar until thick, then fold in chocolate mixture.\n4. Add flour and vanilla, mix gently.\n5. Pour into ramekins and bake 12–14 minutes.\n6. Invert onto plates and serve immediately.",
                Ratings = [5, 5, 5, 4, 5]
            },
            new()
            {
                Id = 7, Title = "Guacamole", Category = "Mexican",
                Ingredients = "Avocados\nLime juice\nCilantro\nRed onion\nJalapeño\nTomato\nSalt\nGarlic",
                Steps = "1. Halve and pit avocados, scoop into a bowl.\n2. Mash to desired consistency.\n3. Stir in diced onion, tomato, jalapeño, and minced garlic.\n4. Add lime juice, chopped cilantro, and salt.\n5. Mix well and taste for seasoning.\n6. Serve with tortilla chips.",
                Ratings = [4, 5, 5]
            },
            new()
            {
                Id = 8, Title = "Miso Ramen", Category = "Asian",
                Ingredients = "Ramen noodles\nMiso paste\nChicken broth\nSoy sauce\nSoft-boiled egg\nGreen onions\nCorn\nNori\nSesame oil\nGarlic",
                Steps = "1. Bring chicken broth to a simmer.\n2. Whisk in miso paste and soy sauce.\n3. Cook ramen noodles according to package directions.\n4. Divide noodles into bowls and ladle broth over them.\n5. Top with halved soft-boiled egg, corn, nori, and green onions.\n6. Drizzle with sesame oil and serve.",
                Ratings = [5, 4, 4, 5]
            }
        ];
        _nextId = 9;
    }

    public IReadOnlyList<string> GetCategories()
    {
        lock (_lock)
        {
            return _recipes.Select(r => r.Category).Distinct().Order().ToList();
        }
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        lock (_lock)
        {
            return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
        }
    }

    public Recipe? GetById(int id)
    {
        lock (_lock)
        {
            return _recipes.FirstOrDefault(r => r.Id == id);
        }
    }

    public void AddRating(int recipeId, int stars)
    {
        lock (_lock)
        {
            var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
            recipe?.Ratings.Add(Math.Clamp(stars, 1, 5));
        }
    }

    public Recipe AddRecipe(string title, string category, string ingredients, string steps)
    {
        lock (_lock)
        {
            var recipe = new Recipe
            {
                Id = _nextId++,
                Title = title,
                Category = category,
                Ingredients = ingredients,
                Steps = steps
            };
            _recipes.Add(recipe);
            return recipe;
        }
    }
}

