arguments.file_text:
@* Interactive star-rating widget — only this component needs Server interactivity *@
@rendermode InteractiveServer

<div class="star-rating d-inline-flex align-items-center gap-2">
    <span class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            int star = i;
            <span class="star @(star <= _selectedRating ? "filled" : "")"
                  role="button"
                  title="Rate @star star(s)"
                  @onclick="() => Rate(star)">
                ★
            </span>
        }
    </span>
    <small class="text-muted">
        @if (TotalRatings > 0)
        {
            <text>@AverageRating.ToString("F1") avg (@TotalRatings ratings)</text>
        }
        else
        {
            <text>No ratings yet</text>
        }
    </small>
    @if (_submitted)
    {
        <span class="badge bg-success fade-in">Thanks!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int TotalRatings { get; set; }
    [Parameter] public EventCallback<int> OnRate { get; set; }

    private int _selectedRating;
    private bool _submitted;

    private async Task Rate(int stars)
    {
        _selectedRating = stars;
        _submitted = true;
        await OnRate.InvokeAsync(stars);
    }
}

.star-rating .star {
    font-size: 1.6rem;
    color: #ccc;
    cursor: pointer;
    transition: color 0.15s, transform 0.15s;
    user-select: none;
}

.star-rating .star:hover,
.star-rating .star.filled {
    color: #f5a623;
}

.star-rating .star:hover {
    transform: scale(1.2);
}

.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
}

@* Interactive star-rating widget — only this component needs Server interactivity *@
@rendermode InteractiveServer

<div class="star-rating d-inline-flex align-items-center gap-2">
    <span class="stars">
        @for (int i = 1; i <= 5; i++)
        {
            int star = i;
            <span class="star @(star <= _selectedRating ? "filled" : "")"
                  role="button"
                  title="Rate @star star(s)"
                  @onclick="() => Rate(star)">
                ★
