arguments.file_text:
@page "/recipes/{Category}"
@using RecipeCommunity.Services

@inject RecipeService RecipeService

<PageTitle>@Category Recipes</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@Category</li>
    </ol>
</nav>

<h2>@Category Recipes</h2>

@{
    var recipes = RecipeService.GetByCategory(Category);
}

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="text-muted mb-1">
                            @if (recipe.Ratings.Count > 0)
                            {
                                <text>⭐ @recipe.AverageRating.ToString("F1") (@recipe.Ratings.Count ratings)</text>
                            }
                            else
                            {
                                <text>No ratings yet</text>
                            }
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-primary mt-2">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string Category { get; set; } = string.Empty;
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@using RecipeCommunity.Components.Shared

@inject RecipeService RecipeService

@if (_recipe is null)
{
    <PageTitle>Recipe Not Found</PageTitle>
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <PageTitle>@_recipe.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/recipes/@_recipe.Category">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        </ol>
    </nav>

    <h2>@_recipe.Title</h2>
    <span class="badge bg-secondary mb-3">@_recipe.Category</span>

    <StarRating RecipeId="@_recipe.Id"
                AverageRating="@_recipe.AverageRating"
                TotalRatings="@_recipe.Ratings.Count"
                OnRate="HandleRating" />

    <hr />

    <div class="row mt-3">
        <div class="col-md-5">
            <h4>🥘 Ingredients</h4>
            <ul class="list-group list-group-flush">
                @foreach (var item in _recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                {
                    <li class="list-group-item">@item.Trim()</li>
                }
            </ul>
        </div>
        <div class="col-md-7">
            <h4>📋 Steps</h4>
            @foreach (var step in _recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
            {
                <p>@step.Trim()</p>
            }
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private RecipeCommunity.Models.Recipe? _recipe;

    protected override void OnInitialized()
    {
        _recipe = RecipeService.GetById(Id);
    }

    private void HandleRating(int stars)
    {
        RecipeService.AddRating(Id, stars);
        _recipe = RecipeService.GetById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Services

@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe</PageTitle>

<h2>📝 Submit a Recipe</h2>
<p>Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe "<em>@_title</em>" has been added.
        <a href="/recipe/@_newRecipeId">View it here</a>.
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="_model.Title" placeholder="e.g. Grandma's Apple Pie" />
            <ValidationMessage For="() => _model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="_model.Category">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Asian">Asian</option>
                <option value="Mexican">Mexican</option>
                <option value="Desserts">Desserts</option>
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => _model.Category" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="_model.Ingredients"
                           placeholder="Flour&#10;Sugar&#10;Butter&#10;Apples" />
            <ValidationMessage For="() => _model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="_model.Steps"
                           placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;3. ..." />
            <ValidationMessage For="() => _model.Steps" />
        </div>

        <button type="submit" class="btn btn-success">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel _model = new();
    private bool _submitted;
    private string _title = string.Empty;
    private int _newRecipeId;

    private void HandleSubmit()
    {
        var recipe = RecipeService.AddRecipe(_model.Title, _model.Category, _model.Ingredients, _model.Steps);
        _title = recipe.Title;
        _newRecipeId = recipe.Id;
        _submitted = true;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        [System.ComponentModel.DataAnnotations.StringLength(100, ErrorMessage = "Title must be 100 characters or fewer.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required.")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required.")]
        public string Steps { get; set; } = string.Empty;
    }
}

